const res = $input.first().json;

const profile = res.profile || null;
const intent = res.intent || null;
const messageObj = res.message || {};

const apiFailed = intent === null;
const requiresPersonal = intent?.requires_personal_data === true;

// Bryan's API only sets code="PERSONAL_DATA" when true, leaves empty when false.
// We must never send an empty string — use "POLICY" as the non-personal code.
const rawCode = (intent?.code || '').trim();
let intentCode;
if (rawCode !== '') {
  intentCode = rawCode;
} else if (requiresPersonal) {
  intentCode = 'PERSONAL_DATA';
} else {
  intentCode = 'POLICY';
}

const isPersonalData = (intentCode === 'PERSONAL_DATA') && profile !== null;
const role = res.user_role === 'va' ? 'VA' : 'Support';

return [{
  json: {
    role,
    profile: profile || {},
    email: profile?.Email || profile?.email || '',
    profile_id: profile?._id || '',
    intent_code: intentCode,
    intent_confidence: intent?.confidence || 0,
    intent_reason: intent?.reason || '',
    intent_tokens: intent?.tokens || 0,
    intent_model: intent?.model || '',
    intent_requires_personal: requiresPersonal,
    is_personal_data: isPersonalData,
    api_ok: !apiFailed,
    normalized_message: messageObj.normalized || '',
    message_language: messageObj.language || 'English',
    message_tokens_used: messageObj.tokens_used || 0,
    pto: res.pto || [],
    overtime: res.overtime || [],
    cos: res.cos || [],
    disputes: res.disputes || []
  }
}];

const classifyData = $('Parse Classify Response').first().json;
const role = classifyData.role; // 'VA' or 'Support'
const profile = classifyData.profile || {};
const email = classifyData.email;
const profileId = classifyData.profile_id;

// ── IDENTITY FIELDS ──────────────────────────────────────────────────────────
const name        = profile['Full Name'] || profile['full_name'] || profile['Name'] || profile['name'] || 'Unknown';
const designation = profile['Designation'] || profile['designation'] || 'N/A';
const department  = profile['Department'] || profile['department'] || 'N/A';
const contractorId = profile['MV Record No'] || profile['Contractor ID'] || profile['contractor_id'] || 'N/A';
const status      = profile['Status'] || profile['status'] || 'N/A';
const startDateRaw = profile['Start Date'] || profile['start_date'] || '';
const daysActive  = profile['Days Active'] || profile['days_active'] || 'N/A';
const ptFt        = profile['PT/FT'] || profile['pt_ft'] || 'N/A';
const payType     = profile['Pay Type'] || profile['pay_type'] || 'N/A';
const hourlyRate  = profile['Hourly Rate'] || profile['hourly_rate'] || null;
const clientRate  = profile['Client Rate'] || profile['client_rate'] || null;
const bank        = profile['Bank'] || profile['bank'] || 'N/A';
const flexiTime   = profile['Flexi time?'] || profile['Flexi Time'] || profile['flexi_time'] || 'N/A';
const clockedIn   = profile['Clocked In?'] ?? profile['clocked_in'] ?? null;
const timezone    = profile['Time zone'] || profile['timezone'] || 'CST';

// ── FORMAT START DATE ────────────────────────────────────────────────────────
let startDateFormatted = 'N/A';
if (startDateRaw) {
  try {
    const dt = new Date(startDateRaw);
    startDateFormatted = dt.toLocaleDateString('en-US', {
      year: 'numeric', month: 'long', day: 'numeric', timeZone: 'UTC'
    });
  } catch(e) {
    startDateFormatted = startDateRaw.split('T')[0];
  }
}

// ── PARSE BUBBLE SCHEDULE TIMES TO LOCAL ────────────────────────────────────
function parseTime(isoStr, tz) {
  if (!isoStr || isoStr === 'N/A') return 'N/A';
  try {
    const offsets = { CST: -6, CDT: -5, EST: -5, EDT: -4, PST: -8, PDT: -7, PHT: 8 };
    const dt = new Date(isoStr);
    const offsetHrs = offsets[tz] ?? -6;
    const local = new Date(dt.getTime() + offsetHrs * 3600 * 1000);
    const h = local.getUTCHours();
    const m = local.getUTCMinutes().toString().padStart(2, '0');
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    return `${h12}:${m} ${ampm} ${tz}`;
  } catch(e) {
    return isoStr.substring(11, 16);
  }
}

// ── BUILD SCHEDULE ───────────────────────────────────────────────────────────
const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];
const scheduleLines = [];

for (const day of days) {
  const hoursVal = profile[`${day} Hours`] ?? profile[`${day} hours`] ?? null;
  const lunchVal = profile[`${day} Lunch`] ?? profile[`${day} lunch`] ?? 'N/A';
  const startRaw = profile[`${day} Start`];
  const endRaw   = profile[`${day} End`];

  if (startRaw && endRaw) {
    const startStr = parseTime(startRaw, timezone);
    const endStr   = parseTime(endRaw, timezone);
    const hrs      = hoursVal !== null ? `${hoursVal}h` : '';
    scheduleLines.push(`  ${day}: ${startStr} – ${endStr}${hrs ? ' (' + hrs + ')' : ''} | Lunch: ${lunchVal}`);
  } else {
    scheduleLines.push(`  ${day}: Schedule not set`);
  }
}

const restDaysRaw = profile['Rest day'] || profile['rest_day'] || profile['Rest Day'] || [];
const restDays = Array.isArray(restDaysRaw) ? restDaysRaw.join(', ') : String(restDaysRaw);
if (restDays) scheduleLines.push(`  Rest Days: ${restDays}`);

// ── PTO BALANCE ──────────────────────────────────────────────────────────────
const leaveCredit = profile['Leave Credit'] ?? profile['leave_credit'] ?? profile['Leave_credit'] ?? null;
const usedPTORaw  = profile['Used PTO'] ?? profile['used_PTO'] ?? profile['used_pto'] ?? null;
const usedPTO     = usedPTORaw !== null ? usedPTORaw : 0;
const totalCredits = leaveCredit !== null ? leaveCredit : 'N/A';
const availablePTO = (leaveCredit !== null && usedPTORaw !== null)
  ? (leaveCredit - usedPTORaw)
  : (leaveCredit ?? 'N/A');

const roleLabel = role === 'VA'
  ? 'VA Contractor (Virtual Assistant) — PTO accumulates monthly while with a client'
  : 'Support Team Contractor — PTO awarded in bulk at start of calendar year';
const roleOpposite = role === 'VA' ? 'Support Team' : 'VA';

// ── PTO REQUESTS ─────────────────────────────────────────────────────────────
// NOTE: Bryan's API returns plain arrays, NOT n8n item wrappers — no .json needed
const ptoItems = classifyData.pto || [];

const pendingPTO = ptoItems.filter(item => {
  const s = (item['Status'] || item['status'] || '').toLowerCase().trim();
  return s === 'pending' || s === 'submitted' || s === 'for approval' || s === 'pending approval';
});

const pendingPTOLines = pendingPTO.length > 0
  ? pendingPTO.map(item => {
      const dateText = item['Date (text)'] || item['date_text'] || null;
      const dateRaw  = item['Date'] || item['date'] || null;
      const date = dateText || (dateRaw ? dateRaw.split('T')[0] : 'N/A');
      const type = item['PTO Type'] || item['Type'] || item['pto_type'] || 'N/A';
      return `  - ${date} | ${type} | PENDING APPROVAL`;
    }).join('\n')
  : '  None pending';

const allPTOLines = ptoItems.length > 0
  ? ptoItems.slice(0, 15).map(item => {
      const dateText = item['Date (text)'] || item['date_text'] || null;
      const dateRaw  = item['Date'] || item['date'] || item['Date requested'] || null;
      const date = dateText || (dateRaw ? dateRaw.split('T')[0] : 'N/A');
      const type    = item['PTO Type'] || item['Type'] || item['pto_type'] || 'N/A';
      const s       = item['Status'] || item['status'] || 'N/A';
      const reason  = item['Reason'] || item['reason'] || item['Notes'] || '';
      const upcoming = new Date(date) >= new Date(new Date().setHours(0,0,0,0));
      const tag = upcoming ? '[UPCOMING]' : '[PAST]';
      return `  ${tag} ${date} | ${type} | ${s}${reason ? ' | ' + reason : ''}`;
    }).join('\n')
  : '  None on record';

// ── OT REQUESTS ──────────────────────────────────────────────────────────────
const otItems = classifyData.overtime || [];
let totalOTHours = 0;

const allOTLines = otItems.length > 0
  ? otItems.slice(0, 10).map(item => {
      const date = (item['Date'] || item['date'] || item['OT Date'] || item['Created Date'] || 'N/A').split('T')[0];
      const s    = item['Status'] || item['status'] || 'N/A';
      const hrs  = item['Overtime hours'] || item['overtime_hours'] || item['Hours'] || item['OT Hours'] || 0;
      if (typeof hrs === 'number') totalOTHours += hrs;
      return `  - ${date} | ${s} | ${hrs ? hrs + ' hrs' : 'hrs N/A'}`;
    }).join('\n')
  : '  None on record';

// ── COS / SCHEDULE REQUESTS ──────────────────────────────────────────────────
const cosItems = classifyData.cos || [];

const allCOSLines = cosItems.length > 0
  ? cosItems.slice(0, 5).map(item => {
      const date     = (item['COS 1 Date'] || item['Created Date'] || item['Created_Date'] || item['date'] || 'N/A').split('T')[0];
      const s        = item['Status'] || item['status'] || 'N/A';
      const reason   = item['Reason'] || item['reason'] || '';
      const newSched = item['New Schedule'] || item['new_schedule'] || item['Requested Schedule'] || '';
      return `  - ${date} | ${s}${newSched ? ' | New: ' + newSched : ''}${reason ? ' | Reason: ' + reason : ''}`;
    }).join('\n')
  : '  None on record';

// ── DISPUTES ─────────────────────────────────────────────────────────────────
const dispItems = classifyData.disputes || [];
const now = new Date();
const dispThisMonth = dispItems.filter(item => {
  const d = new Date(item['Created Date'] || item['date'] || '');
  return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
});

const allDispLines = dispItems.length > 0
  ? dispItems.slice(0, 5).map(item => {
      const disputedDateRaw = item['Requested In'] || item['Date requested'] || item['Created Date'] || item['date'] || null;
      const date      = disputedDateRaw ? disputedDateRaw.split('T')[0] : 'N/A';
      const s         = item['Status'] || item['status'] || 'N/A';
      const wholeHalf = item['Whole day/half day'] || item['Whole/half day'] || null;
      const wholeHalfLabel = wholeHalf ? ` (${wholeHalf})` : '';
      const reason    = item['Dispute Reason'] || item['dispute_reason'] || item['Reason'] || item['reason'] || '';
      const filedDate = (item['Created Date'] || '').split('T')[0];
      return `  - Disputed date: ${date}${wholeHalfLabel} | Status: ${s}${filedDate ? ' | Filed: ' + filedDate : ''}${reason ? '\n    Reason: ' + reason : ''}`;
    }).join('\n')
  : '  None on record';

// ── ASSEMBLE FULL CONTEXT ────────────────────────────────────────────────────
const bubbleData = [
  '=== CONTRACTOR PERSONAL DATA ===',
  '',
  '--- PROFILE / IDENTITY ---',
  `Name: ${name}`,
  `Role: ${role}`,
  `Email: ${email}`,
  `Designation: ${designation}`,
  `Department: ${department}`,
  `Status: ${status}`,
  `Contractor ID: ${contractorId}`,
  `Profile ID: ${profileId}`,
  `Start Date: ${startDateFormatted}`,
  `Days Active: ${daysActive}`,
  '',
  '--- EMPLOYMENT DETAILS ---',
  `Employment Type: ${ptFt}`,
  `Pay Type: ${payType}`,
  `Contractor Fee (Hourly Rate): ${hourlyRate !== null ? '$' + hourlyRate + '/hr' : 'N/A'}`,
  `Client Rate: ${clientRate !== null ? '$' + clientRate + '/hr' : 'N/A'}`,
  `Time Zone: ${timezone}`,
  `Flexi Time: ${flexiTime}`,
  `Bank: ${bank}`,
  `Currently Clocked In: ${clockedIn === true ? 'Yes' : clockedIn === false ? 'No' : 'N/A'}`,
  '',
  '--- CURRENT SCHEDULE ---',
  ...scheduleLines,
  '',
  '--- PTO / LEAVE CREDITS ---',
  `Contractor Type for PTO Rules: ${roleLabel}`,
  `IMPORTANT: This contractor is a ${role === 'VA' ? 'VA' : 'Support Team'} member.`,
  `Apply ${role === 'VA' ? 'VA' : 'Support Team'} PTO rules ONLY.`,
  `Do NOT describe ${roleOpposite} PTO rules to this user. They are not a ${roleOpposite} contractor.`,
  `Total Credits This Year: ${totalCredits}`,
  `Used PTO (SVPTO): ${usedPTO}`,
  `Available PTO Credits: ${availablePTO}`,
  `DIRECT ANSWER FOR PTO BALANCE: ${availablePTO} credits remaining.`,
  `DO NOT volunteer how PTO accumulates unless specifically asked.`,
  `DO NOT state annual credit amounts (10 or 12) when answering a balance question.`,
  '',
  'Pending PTO Requests:',
  pendingPTOLines,
  '',
  'All PTO Request History (newest first):',
  allPTOLines,
  '',
  '--- OVERTIME (OT) ---',
  `Total OT Hours This Year: ${totalOTHours > 0 ? totalOTHours + ' hrs' : 'None filed or 0'}`,
  'OT Request Records:',
  allOTLines,
  '',
  '--- CHANGE OF SCHEDULE (COS) REQUESTS ---',
  'NOTE: The Current Schedule section above is what is on file.',
  'COS Records below are submitted requests (approved or pending):',
  allCOSLines,
  '',
  '--- DISPUTES ---',
  `Disputes Filed This Month: ${dispThisMonth.length}`,
  'Recent Dispute Records (Disputed date = actual attendance date, Filed = submission date):',
  allDispLines,
  '',
  '--- WHAT IS NOT AVAILABLE IN THIS DATA ---',
  'Cannot answer from this context — redirect to the right resource:',
  '  - Daily clock-in/clock-out logs → SV Portal > Attendance Logs',
  '  - Attendance history / time logs → SV Portal > Attendance Logs',
  '  - Payslip / Statement of Fees → finance@scalevirtually.com',
  '  - Future PTO credit projections → Contractor Services',
  '  - Bank account number → do not reveal, redirect to Contractor Services',
  '',
  '--- RESPONSE RULES ---',
  '1. Use exact values from this data. Do not estimate or round.',
  '2. Contractor fee = Hourly Rate field. Say "Your contractor fee is $X/hr."',
  '3. For schedule: read the Current Schedule section above, not the COS records.',
  '4. For PTO balance: use the Available PTO Credits value. The pre-computed answer',
  '   is in "DIRECT ANSWER FOR PTO BALANCE" above — use that exact number.',
  '5. If data shows N/A: say "That information is not on file — check the SV Portal."',
  '6. Never reveal the Bank Account number to anyone.',
  '7. For attendance logs → always redirect to SV Portal > Attendance Logs.',
  '8. For payslip → redirect to Finance Team at finance@scalevirtually.com.',
  '9. NEVER say "I wasn\'t able to pull that up" for OT, COS, Dispute, or PTO.',
  '   Those ARE pre-fetched. If they show "None on record" — say that instead.',
  '   "None on record" = system fetched successfully, nothing exists.',
  '   Only say "I wasn\'t able to pull" for items in the NOT AVAILABLE section above.',
  '10. For disputes: "Disputed date" is the actual attendance date. "Filed" is when submitted.',
  '11. For "what was my last dispute about" — read the Reason field and state it.',
  '12. For PTO role type: always use "Contractor Type for PTO Rules" field above.',
  '    Never infer the role from PTO history or any other field.',
].join('\n');

const bubble_data_escaped = bubbleData
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

return [{ json: {
  bubble_data: bubbleData,
  bubble_data_escaped,
  is_personal_data: true,
  role,
  profile_id: profileId,
  email,
  _debug_profile_keys: Object.keys(profile),
  _debug_available_pto: availablePTO,
  _debug_role_label: roleLabel,
  _debug_hourly_rate: hourlyRate,
  _debug_designation: designation,
  _debug_department: department,
  _debug_pto_count: ptoItems.length,
  _debug_ot_count: otItems.length,
  _debug_cos_count: cosItems.length,
  _debug_disp_count: dispItems.length,
} }];

