  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

return [{
  json: {
    classifier_status: response.meta?.classifier_status || 'OFF_TOPIC',
    content,
    slack_content,
    output: slack_content,
    thread_id: response.thread_id,
    matched_docs: response.matched_docs || [],
    model_used: response.meta?.model_used || '',
    tokens: response.meta?.tokens || 0,
    latency_ms: response.meta?.latency_ms || 0
  }
}];

